CREATE TABLE IF NOT EXISTS technology_partners (id BIGSERIAL PRIMARY KEY, name VARCHAR(180) NOT NULL, partner_type VARCHAR(80) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'ACTIVE', created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS partner_applications (id BIGSERIAL PRIMARY KEY, partner_id BIGINT NOT NULL REFERENCES technology_partners(id), app_name VARCHAR(160) NOT NULL, integration_type VARCHAR(80) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'ACTIVE', created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS partner_contracts (id BIGSERIAL PRIMARY KEY, partner_id BIGINT NOT NULL REFERENCES technology_partners(id), contract_code VARCHAR(60) NOT NULL, starts_at DATE NOT NULL, ends_at DATE NULL, status VARCHAR(30) NOT NULL DEFAULT 'ACTIVE');
CREATE TABLE IF NOT EXISTS partner_certifications (id BIGSERIAL PRIMARY KEY, partner_id BIGINT NOT NULL REFERENCES technology_partners(id), certification_name VARCHAR(140) NOT NULL, level VARCHAR(40) NOT NULL, valid_until DATE NULL);
CREATE TABLE IF NOT EXISTS partner_sla_agreements (id BIGSERIAL PRIMARY KEY, partner_id BIGINT NOT NULL REFERENCES technology_partners(id), response_sla_minutes INT NOT NULL, resolution_sla_minutes INT NOT NULL, active BOOLEAN NOT NULL DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS partner_revenue_share_rules (id BIGSERIAL PRIMARY KEY, partner_id BIGINT NOT NULL REFERENCES technology_partners(id), rule_name VARCHAR(120) NOT NULL, percentage NUMERIC(5,2) NOT NULL);
CREATE TABLE IF NOT EXISTS partner_support_cases (id BIGSERIAL PRIMARY KEY, partner_id BIGINT NOT NULL REFERENCES technology_partners(id), subject VARCHAR(200) NOT NULL, severity VARCHAR(20) NOT NULL, status VARCHAR(30) NOT NULL DEFAULT 'OPEN', created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS partner_integration_reviews (id BIGSERIAL PRIMARY KEY, partner_id BIGINT NOT NULL REFERENCES technology_partners(id), score INT NOT NULL CHECK (score BETWEEN 1 AND 5), notes TEXT NULL, reviewed_at TIMESTAMP NOT NULL DEFAULT NOW());
